sql:
SELECT nuclide_name, neutron_number
FROM nuclides
WHERE is_stable = 1;

SELECT nuclide_name, half_life
FROM nuclides
WHERE nuclide_id = 1;

SELECT nuclide_name, half_life, mode_of_decay, isotopic_abundance, nuclide_symbol, discovery_year
FROM nuclides
WHERE half_life = (SELECT MAX(half_life) FROM nuclides WHERE half_life IS NOT NULL);

SELECT AVG(CAST(decay_energy AS REAL)) AS average_decay_energy
FROM nuclides
WHERE is_stable = 1 OR CAST(half_life AS REAL) > 10000;

SELECT nuclide_name, binding_energy
FROM nuclides
WHERE binding_energy = (
  SELECT MAX(binding_energy)
  FROM nuclides
);

SELECT nuclides.nuclide_name, nuclides.half_life, nuclide_decay_modes.half_life_uncertainty
FROM nuclides
INNER JOIN nuclide_decay_modes ON nuclides.nuclide_id = nuclide_decay_modes.parent_nuclide_id;

external_knowledge:
- 'stable nuclides' refers to those nuclides that do not undergo radioactive decay;
- Frequency of appearance here is indicated by the count of stable instances for each nuclide;
- 'Typical half-life' and 'natural abundance' are averages calculated across all entries, offering a general sense of what these values tend to be for each nuclide;
- Nuclides with higher natural abundance are more commonly found in nature.

sql:
SELECT discovery_year, COUNT(*) as num_nuclides_discovered 
FROM nuclides 
GROUP BY discovery_year;

external_knowledge:
- "elements known to decay through processes involving protons" refers to nuclides with decay modes that include 'Proton%' in the decay mode name;
- Key properties include decay energy, decay constant, and uncertainty in the half-life measurement;
- The term "how reliable the half-life measurements are" refers to the half-life uncertainty.

sql:
SELECT * 
FROM nuclide_measurements 
WHERE measurement_id = (SELECT MAX(measurement_id) FROM nuclide_measurements);

SELECT AVG(CAST(binding_energy AS REAL)) AS average_binding_energy
FROM nuclides
WHERE nuclide_symbol = 'Tb';

SELECT DISTINCT n.nuclide_name
FROM nuclides n
WHERE CAST(SUBSTR(n.half_life, 1, INSTR(n.half_life, ' ') - 1) AS REAL) > 2;
